parameters.jsCode:
const body = $json.body;
const raw = typeof body === 'string' ? body : JSON.stringify(body ?? {});
const compact = raw
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const parserType = $json.parser_type || 'generic';
let title = `${$json.service} / ${$json.source}`;
let priceBefore = '';
let priceNow = '';
let discountText = '';
let dealType = 'unknown';
if (parserType === 'reddit_json') {
  title = `${$json.service} reddit feed`;
  dealType = 'community_signal';
}
if (/lifetime/i.test(compact)) dealType = 'lifetime_deal';
if (/% off|discount|save \$/i.test(compact)) dealType = 'discount';
const content = compact.slice(0, 12000);
const normalizedUrl = ($json.url || '').replace(/\?.*$/, '');
const contentHash = require('crypto').createHash('sha256').update(`${$json.service}|${$json.source}|${normalizedUrl}|${content.slice(0, 4000)}`).digest('hex');
return [{ json: {
  run_id: $json.run_id,
  mode: $json.mode,
  current_date: $json.current_date,
  source_id: $json.source_id,
  service: $json.service,
  source: $json.source,
  source_url: $json.url,
  normalized_url: normalizedUrl,
  raw_text: content,
  content_hash: contentHash,
  title,
  price_before: priceBefore,
  price_now: priceNow,
  discount_text: discountText,
  deal_type: dealType,
}}];

const items = $items('Normalize Successful Fetch', 0, 0).map((x) => x.json);
const run = $('Create Run').first().json;
return [{ json: {
  run_id: run.id,
  mode: run.mode,
  current_date: new Date().toISOString(),
  raw_items_json: JSON.stringify(items),
  raw_items_count: items.length,
}}];

const agg = $('Aggregate Successes').first().json;
return [{ json: {
  run_id: agg.run_id,
  mode: agg.mode,
  current_date: agg.current_date,
  raw_items_count: agg.raw_items_count,
  raw_items_json: agg.raw_items_json,
  prev_report: $json.prev_report || '',
  active_deals_json: JSON.stringify($json.active_deals || []),
}}];

