parameters.jsCode:
const responseBody = $json.body ?? {};
let content = responseBody.output_text;
if (!content && Array.isArray(responseBody.output)) {
  const textChunks = [];
  for (const item of responseBody.output) {
    if (!Array.isArray(item.content)) continue;
    for (const part of item.content) {
      if (part.type === 'output_text' && part.text) textChunks.push(part.text);
    }
  }
  content = textChunks.join('\n');
}
let report;
try {
  report = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  report = {
    summary: { date: new Date().toISOString().slice(0, 10), top_deals_count: 0, new_count: 0, changed_count: 0, expired_count: 0 },
    top_deals: [], expired: [], notes: ['Invalid OpenAI JSON', String(error.message || error)]
  };
}
const prep = $('Prepare AI Payload').first().json;
const topDeals = Array.isArray(report.top_deals) ? report.top_deals : [];
const expired = Array.isArray(report.expired) ? report.expired : [];
const lines = ['AI TOOLS DEAL MONITOR', `Date: ${report.summary?.date || new Date().toISOString().slice(0, 10)}`, '', 'Top deals today:'];
if (!topDeals.length) lines.push('No high-confidence deals found.');
for (const deal of topDeals.slice(0, 5)) lines.push(`${deal.rank}. ${deal.service} — ${deal.title} (${deal.discount_text})`);
lines.push('', `Fetched sources: ${prep.raw_items_count}`, `New deals: ${report.summary?.new_count ?? 0}`, `Changed: ${report.summary?.changed_count ?? 0}`, `Expired: ${report.summary?.expired_count ?? 0}`);
return [{ json: { run_id: prep.run_id, raw_items_count: prep.raw_items_count, report, telegram_text: lines.join('\n'), top_deals_json: JSON.stringify(topDeals), expired_json: JSON.stringify(expired) } }];

parameters.query:
insert into reports (run_id, report_date, summary_text, report_json, new_count, changed_count, expired_count)
values (
  '{{$json.run_id}}'::uuid,
  current_date,
  '{{$json.telegram_text.replace(/'/g, "''")}}',
  '{{$json.report ? JSON.stringify($json.report).replace(/'/g, "''") : '{}'}}'::jsonb,
  {{$json.report.summary?.new_count || 0}},
  {{$json.report.summary?.changed_count || 0}},
  {{$json.report.summary?.expired_count || 0}}
);

update monitor_runs
set status = 'completed',
    run_finished_at = now(),
    raw_items_count = {{$json.raw_items_count || 0}},
    normalized_items_count = {{ $json.report.summary?.top_deals_count || 0 }}
where id = '{{$json.run_id}}'::uuid;
